params.param:
[
            {name: "Seed command run", type: "command-run", paths: ["contexts/", "projects/"], commands: ["bin/console app:seed-admin --env=dev", "bin/console app:seed-admin --env=dev"], pass: "Command exits 0 on first AND second run (idempotent), and an admin row is present in the dev database afterward", fail: "Non-zero exit, duplicate admin row, or no admin row after the run"},
            {name: "No inlined secret", type: "file-check", paths: ["contexts/", "projects/"], commands: ["grep -rn 'app:seed-admin' contexts/ projects/ to locate the command class, then confirm it reads admin_identifier_env and admin_password_env via getenv/$_ENV and contains NO literal password/secret value"], pass: "Credentials referenced by env-var name only (admin_identifier_env / admin_password_env); no literal secret value in source", fail: "A literal credential value is hardcoded in the command or related source"}
          ]
